mapper.select:
SELECT b.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, brd.brand_nm AS brand_nm, cd_vbc.code_label AS contract_cd_nm FROM sy_vendor_brand b LEFT JOIN sy_site ste ON ste.site_id = b.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = b.vendor_id LEFT JOIN sy_brand brd ON brd.brand_id = b.brand_id LEFT JOIN sy_code cd_vbc ON cd_vbc.code_grp = 'VENDOR_BRAND_CONTRACT' AND cd_vbc.code_value = b.contract_cd
ORDER BY b.vendor_brand_id ASC ORDER BY b.vendor_brand_id DESC ORDER BY b.reg_date ASC ORDER BY b.reg_date DESC ORDER BY b.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT b.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, brd.brand_nm AS brand_nm, cd_vbc.code_label AS contract_cd_nm FROM sy_vendor_brand b LEFT JOIN sy_site ste ON ste.site_id = b.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = b.vendor_id LEFT JOIN sy_brand brd ON brd.brand_id = b.brand_id LEFT JOIN sy_code cd_vbc ON cd_vbc.code_grp = 'VENDOR_BRAND_CONTRACT' AND cd_vbc.code_value = b.contract_cd
ORDER BY b.vendor_brand_id ASC ORDER BY b.vendor_brand_id DESC ORDER BY b.reg_date ASC ORDER BY b.reg_date DESC ORDER BY b.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE sy_vendor_brand
site_id = #{siteId}, vendor_id = #{vendorId}, brand_id = #{brandId}, is_main = #{isMain}, contract_cd = #{contractCd}, start_date = #{startDate}, end_date = #{endDate}, commission_rate = #{commissionRate}, sort_ord = #{sortOrd}, use_yn = #{useYn}, vendor_brand_remark = #{vendorBrandRemark}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE vendor_brand_id = #{vendorBrandId}
